#include <iostream>

#define N 300010

#define MOD 998244353

using namespace std;

typedef long long ll;

ll n,a,b,c;

ll P,Q[N];

ll extgcd(ll a,ll b,ll &x,ll &y) {

	if(b) {

		ll k=extgcd(b,a%b,x,y);

		ll t=x;x=y;

		y=t-a/b*y;

		return k;

	} else {

		x=1;y=0;

		return a;

	}

}

inline ll C(int x) {

	return P*Q[x]%MOD*Q[n-x]%MOD;

}

inline ll solve() {

	ll x,y,d,k,m;

	d=extgcd(a,b,x,y);

	if(c%d) return 0;

	k=c/d;x*=k;y*=k;

	if(y<0) {

		k=x;x=y;y=k;

		k=a;a=b;b=k;

	}

	k=b/d;

	m=(x-k+1)/k;

	x-=m*b/d,y+=m*a/d;

	P=Q[1]=1;

	for(int i=2;i<=n;++i) {

		P=P*i%MOD;

		Q[i]=(MOD-MOD/i)*Q[MOD%i]%MOD;

	}

	Q[0]=1;for(int i=2;i<=n;++i) Q[i]=Q[i]*Q[i-1]%MOD;

	ll ans=0;

	for(;x<=n&&y>=0;x+=b/d,y-=a/d) {

		if(y<=n) {

			ans+=C(x)*C(y);

			ans%=MOD;

		}

	}

	return ans;

}

int main() {

	cin>>n>>a>>b>>c;

	cout<<solve()<<endl;

	return 0;

}

