	if(c%d) return 0;

	k=c/d;x*=k;y*=k;

	if(y<0) {

		k=x;x=y;y=k;

		k=a;a=b;b=k;

	}

	k=b/d;

	m=(x-k+1)/k;

	x-=m*b/d,y+=m*a/d;

